"use strict";(self.webpackChunkpims_manual=self.webpackChunkpims_manual||[]).push([[581],{5610:e=>{e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Introduction","href":"/pimsKB/docs/intro","docId":"intro","unlisted":false},{"type":"category","label":"Appendix","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Appendix A \u2013 Course Codes","href":"/pimsKB/docs/Appendix/appendix-A","docId":"Appendix/appendix-A","unlisted":false},{"type":"link","label":"Appendix B \u2013 Staff Assignment Codes","href":"/pimsKB/docs/Appendix/appendix-B","docId":"Appendix/appendix-B","unlisted":false}]},{"type":"category","label":"Templates","collapsible":true,"collapsed":true,"items":[{"type":"category","label":"Enrollment","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"School Enrollment Template","href":"/pimsKB/docs/Templates/Enrollment/school-enrollment-template","docId":"Templates/Enrollment/school-enrollment-template","unlisted":false}]},{"type":"link","label":"Templates","href":"/pimsKB/docs/Templates/intro","docId":"Templates/intro","unlisted":false}]},{"type":"link","label":"Courses to be Reported in PIMS","href":"/pimsKB/docs/courses-to-be-reported","docId":"courses-to-be-reported","unlisted":false},{"type":"link","label":"Curriculum, Assessment, and Instruction","href":"/pimsKB/docs/curriculum-assessment-instruction","docId":"curriculum-assessment-instruction","unlisted":false},{"type":"link","label":"Race, Ethnicity, Gender","href":"/pimsKB/docs/race-ethnicity-gender-standards","docId":"race-ethnicity-gender-standards","unlisted":false},{"type":"link","label":"Staff to be Reported in PIMS","href":"/pimsKB/docs/staff-to-be-reported","docId":"staff-to-be-reported","unlisted":false},{"type":"link","label":"Students to be Reported in PIMS","href":"/pimsKB/docs/students-to-be-reported","docId":"students-to-be-reported","unlisted":false}]},"docs":{"Appendix/appendix-A":{"id":"Appendix/appendix-A","title":"Appendix A \u2013 Course Codes","description":"Course Codes are found in the Course Codes \u2013 App A spreadsheet on the Pennsylvania Department of Education \\\\> Data and Reporting \\\\> PIMS \\\\> Manuals and Calendar page.","sidebar":"tutorialSidebar"},"Appendix/appendix-B":{"id":"Appendix/appendix-B","title":"Appendix B \u2013 Staff Assignment Codes","description":"Chief School Administrator Assignment Codes (numerical order) are found in the Staff Assignments \u2013","sidebar":"tutorialSidebar"},"courses-to-be-reported":{"id":"courses-to-be-reported","title":"Courses to be Reported in PIMS","description":"LEAs are required to submit all courses, course instructor assignments, and student course enrollments, in all academic subject areas for both elementary and secondary. To meet federal reporting requirements, LEAs are expected to map all local courses to state course codes (PIMS \\\\> Manuals and Calendar \\\\> Course Codes \u2013 App A).","sidebar":"tutorialSidebar"},"curriculum-assessment-instruction":{"id":"curriculum-assessment-instruction","title":"Curriculum, Assessment, and Instruction","description":"Division of Assessment and Accountability (DAA)","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction","description":"The Pennsylvania Information Management System (PIMS) is a collaborative effort of the Pennsylvania Department of Education (PDE) and local education agencies (LEA) across the commonwealth. PIMS is a statewide, longitudinal data system (SLDS) that efficiently and accurately manages, analyzes, disaggregates, and uses individual data for each student served by Pennsylvania\u2019s pre-K through grade 12 public education system.","sidebar":"tutorialSidebar"},"race-ethnicity-gender-standards":{"id":"race-ethnicity-gender-standards","title":"Race, Ethnicity, Gender","description":"Federal Race, Ethnicity, and Gender Standards","sidebar":"tutorialSidebar"},"staff-to-be-reported":{"id":"staff-to-be-reported","title":"Staff to be Reported in PIMS","description":"Professional Personnel","sidebar":"tutorialSidebar"},"students-to-be-reported":{"id":"students-to-be-reported","title":"Students to be Reported in PIMS","description":"All Pre-K through grade 12 and Adult Affidavit Program (AAP) students enrolled in a public school and students enrolled in an Approved Private School (APS) or Private Residential Rehabilitation Institution (PRRI) in Pennsylvania shall be reported in PIMS. Student data will be submitted through templates. See the template section of this document for more information.","sidebar":"tutorialSidebar"},"Templates/Enrollment/school-enrollment-template":{"id":"Templates/Enrollment/school-enrollment-template","title":"School Enrollment Template","description":"School Enrollment Template Documentation","sidebar":"tutorialSidebar"},"Templates/intro":{"id":"Templates/intro","title":"Templates","description":"Templates are the files that will be used to load data into the PIMS data warehouse. Template specifications define the fields required for each file submitted to PIMS. Each template maps directly to a separate table in the data warehouse. By using templates, LEAs are able to use a variety of file formats (comma delimited, tab delimited, pipe) to transmit data as long as all fields within the template are accounted for. Within a given template not all eScholar-defined fields are collected by PDE.","sidebar":"tutorialSidebar"}}}')}}]);